const carBinary = $("Download Car Image").first().binary.data;
const downloadedStudioItems = $("Download Studio Image").all();

let studioBinary = null;
let logoBinary = null;

for (const item of downloadedStudioItems) {
  const name = item.json.name ? item.json.name.toLowerCase() : "";
  if (name === "virtual_studio.png") {
    studioBinary = item.binary.data;
  } else if (name === "logo.png") {
    logoBinary = item.binary.data;
  }
}

if (!studioBinary && downloadedStudioItems.length > 0) {
    studioBinary = downloadedStudioItems[0].binary.data;
}

let carJson = {};
try { carJson = $("Loop").item.json; } catch(e) { carJson = $("List Car Images").first().json; }

return {
  json: { ...carJson },
  binary: {
    car: carBinary,
    ...(studioBinary ? { studio: studioBinary } : {}),
    ...(logoBinary ? { logo: logoBinary } : {})
  }
};

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binary = item.binary || {};

  const parts = [
    { 
      text: "Analyze the provided car image and determine its type: Exterior, Interior, or Engine/Detail.\n\n1. If Exterior: Remove the original background and place the car seamlessly into the provided virtual studio background image. Ensure realistic lighting and shadows.\n2. If Interior or Engine/Detail: Do NOT use the provided virtual studio background. Instead, cleanly mask out the messy outside background (e.g., the view out of the windows or the surrounding area outside the engine bay) and replace it with a clean, solid light green background (matching the branding of the studio).\n3. License Plate Replacement: If the front or back of the car is visible and a license plate is present, replace the license plate entirely with the provided business logo image.\n\nIMPORTANT NEGATIVE INSTRUCTIONS:\n- Do NOT add reflections under the car.\n- Do NOT alter the car's original shape, color, or details.\n\nMaintain the original aspect ratio and generate a high-quality 4k image. Output ONLY the generated image."
    }
  ];

  if (binary.car) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'car');
    parts.push({
      inlineData: {
        mimeType: binary.car.mimeType,
        data: buffer.toString('base64')
      }
    });
  }

  if (binary.studio) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'studio');
    parts.push({
      inlineData: {
        mimeType: binary.studio.mimeType,
        data: buffer.toString('base64')
      }
    });
  }

  if (binary.logo) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'logo');
    parts.push({
      inlineData: {
        mimeType: binary.logo.mimeType,
        data: buffer.toString('base64')
      }
    });
  }

  const reqBody = {
    contents: [
      {
        parts: parts
      }
    ],
    generationConfig: {
      responseModalities: ["IMAGE"]
    }
  };

  results.push({
    json: {
      reqBody: reqBody,
      ...item.json
    },
    binary: item.binary
  });
}

return results;

const items = $input.all();
const output = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const parts = item.json.candidates && item.json.candidates[0] && item.json.candidates[0].content && item.json.candidates[0].content.parts;

  if (!parts) {
    throw new Error("Invalid Gemini response: " + JSON.stringify(item.json));
  }

  const imagePart = parts.find(p => p.inlineData || p.inline_data);

  if (!imagePart) {
    throw new Error("No image data found in Gemini response");
  }

  const inline = imagePart.inlineData || imagePart.inline_data;
  const base64Data = inline.data;
  const mimeType = inline.mimeType || inline.mime_type || "image/jpeg";

  const buffer = Buffer.from(base64Data, 'base64');

  let carJson = {};
  try { carJson = $("Loop").item.json; } catch(e) { carJson = $("List Car Images").first().json; }
  const originalName = carJson.name || "car.jpg";

  const fileName = originalName.replace(/\.[^/.]+$/, "") + "_studio.jpg";
  const binaryData = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);

  output.push({
    json: { mimeType, originalName, ...item.json },
    binary: {
      data: binaryData
    }
  });
}

return output;
